```class Solution {
    public List<Long> maximumEvenSplit(long finalSum) {
        List<Long> result = new ArrayList<>();
        int n = (int) Math.ceil(Math.sqrt(finalSum));
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= n; j++) {
                if (finalSum % 2 == 0 && i * j * 2 <= finalSum) {
                    result.add(i * j * 2);
                }
            }
        }
        return result;
    }
}
